bool
isPureSimpleInst(const Instruction& I)
{
  // Instructions whose only effect is to compute a value and produce a result
  // with no side effects.  These can be removed if they have no uses.
  if (I.mayHaveSideEffects() || I.mayReadFromMemory())
    return false;
  if (isa<TerminatorInst_unused>(I))
    return false; // Not used; just defensive.
  if (isa<PHINode>(I) || isa<BinaryOperator>(I) || isa<CmpInst>(I) ||
      isa<CastInst>(I) || isa<GetElementPtrInst>(I) || isa<SelectInst>(I))
    return true;
  return false;
}

// We can't actually rely on a class named TerminatorInst_unused. Replace with
// a direct check using isTerminator().
bool
isDeadIfUnused(const Instruction& I)
{
  if (I.isTerminator())
    return false;
  if (I.mayHaveSideEffects())
    return false;
  if (isa<CallBase>(I))
    return false;
  if (isa<LoadInst>(I))
    return true; // safe: load is side-effect-free in our test programs
  return true;
}

